INSERT INTO team_tactic_setups VALUES(1,'2025-26','FC26','optimal','4-2-3-1 Wide','Short Passing','Balanced',52,NULL,'Emery 25/26: positional short build-up from the back (Martínez + Pau Torres BPD) — Short Passing. Defence is a compact 4-4-2 MID-block with opportunistic ball-winning, not an aggressive press or ultra-high line — Balanced, line ~52 (mid). CORRECTION 2026-07-02: previously High/68 from the 23/24 high-line narrative; 25/26-specific analyses (themastermindsite, totalfootballanalysis) and zero counter-goals-conceded contradict it — see tactic_observations scope=defence. Pairs with player_role_map kind=optimal. [2026-07-02 FORMATION PIN: in-game formation fixed to 4-2-3-1 Wide — left attacking slot is LM (WM type), so analysis-label LW prescriptions map to wm_* in-game equivalents and measured-nearest roles were refit vs wm kernels (see transfer_targets LM rows + player_role_map kind=role:LM).]','FINAL (data-only) — 실측·분석 기반 확정. 게임 내 검증은 수동 플레이 환경이라 생략 (사용자 결정 2026-07-05). 이전 게이트: MEDIUM — team-setting mapping grounded in 25/26 analyses + measured heatmaps, but not yet validated in-game. Validate by building the tactic in FC26, saving tactic_code, comparing in-game vs measured heatmaps.');
INSERT INTO team_tactic_setups VALUES(2,'2025-26','FC26','optimal:rogers10','4-2-3-1 Wide','Short Passing','Balanced',47,NULL,'PERSONNEL VARIANT of kind=optimal for the Rogers-at-No.10 XI (e.g. Baturina/Tavernier LM + Rogers CAM). Two data drivers (2026-07-03 인선-전술 분석, docs/20 규칙 B): (1) front-six normalized defensive share drops 31.0%→28.8% (lowest of all variants) — line lowered 52→47 to compensate; (2) attack flips right (unit lane L 18%→12%, Rogers CAM centroid x=57.5) — LEFT exposure is asymmetric, so pair with LB Attack compensation + RM wm_widemid/Support (rule A-3). Build-up stays Short Passing (deep drop-in creators support it). Counter is a contested/away experiment only.','FINAL (data-only) — 실측·분석 기반 확정. 게임 내 검증은 수동 플레이 환경이라 생략 (사용자 결정 2026-07-05). 이전 게이트: MEDIUM — same in-game-unvalidated caveat as kind=optimal; validate via tactic_code + in-game heatmap comparison.');
INSERT INTO team_tactic_setups VALUES(3,'2025-26','FC26','optimal:vs-strong','4-2-3-1 Wide','Short Passing','Deep',43,NULL,'vs 리버풀·시티급 강팀: 물러나 흡수. 실측 근거 리버풀전 PPDA 20.43, 시티전 14.44 (에메리는 강팀 상대 라인 내려 블록 유지). 문서 FC26_에메리_빌라_전술세팅.md §1 흡수. 빌드업은 base Short Passing 유지(문서는 Balanced 주장 — 미해결, tactic_code 검증 필요). [결과 보강 2026-07-02: 저점유(<=48%) 국면 14승1무2패(+1.00) — 첼시·토트넘 원정, 리버풀·시티·아스널전 포함. 흡수-역습이 팀의 최강 얼굴임을 결과가 확인. tactic_observations scope=possession.]','FINAL (data-only) — 실측·분석 기반 확정. 게임 내 검증은 수동 플레이 환경이라 생략 (사용자 결정 2026-07-05). 이전 게이트: MEDIUM — 게임 미검증, PPDA 실측 기반');
INSERT INTO team_tactic_setups VALUES(4,'2025-26','FC26','optimal:vs-weak','4-2-3-1 Wide','Short Passing','High',67,NULL,'vs 약팀·로우블록: 전방 압박 극대화. 실측 근거 울브스전 PPDA 4.99, 선덜랜드전 5.78. High까지가 상한(Aggressive 미사용 — 에메리는 선택적 압박, 게겐프레싱 아님). 문서 §1 흡수. [결과 보강 2026-07-02: 점유-성적 역상관 실측(r=-0.29, 45경기)이 이 변형의 필요를 결과 축에서 확인 — 고점유(>=55%) 국면 8승3무6패로 표본 내 패배 전부가 여기 몰림(CP H 0-3, 브렌트포드 H/A, 에버턴 H, 고어헤드). 로우블록 공략이 시즌의 약점 국면이었음. tactic_observations scope=possession.]','FINAL (data-only) — 실측·분석 기반 확정. 게임 내 검증은 수동 플레이 환경이라 생략 (사용자 결정 2026-07-05). 이전 게이트: MEDIUM — 게임 미검증, PPDA 실측 기반 | 점유-결과 실측으로 필요성 HIGH, 설정값 자체는 게임 검증 대상.');
INSERT INTO team_tactic_setups VALUES(5,'2025-26','FC26','optimal:lead','4-2-3-1 Wide','Short Passing','Deep',45,NULL,'리드 관리(후반 잠그기): 4-4-2 콤팩트 블록으로 템포 죽이기, 숏패싱 유지. 문서 §1 흡수. rest-defense(풀백 한 번에 한 명만 전진)가 역습 실점 0의 핵심.','FINAL (data-only) — 실측·분석 기반 확정. 게임 내 검증은 수동 플레이 환경이라 생략 (사용자 결정 2026-07-05). 이전 게이트: MEDIUM — 게임 미검증');
INSERT INTO team_tactic_setups VALUES(6,'2026-27','FC26','projected','4-2-3-1 Wide','Short Passing','Balanced',52,NULL,'26/27 예상 XI (2026-07-22 이적 전망 기준): 마르티네스 gk_ballplaying/Build-Up — 캐시 fb_wingback/Balanced·콘사 cb_bpd/Aggressive·파우 토레스 cb_bpd/Build-Up·에스투피냔 fb_att_wb/Support — 고메스(LDM) dm_holding/Ball-Winning·카마라(RDM) dm_holding/Ball-Winning — 맥긴(RM) wm_widemid/Support·만잠비(CAM) cam_halfwinger/Balanced·가르나초(LM) wm_insidefwd/Attack — 왓킨스 st_advanced/Versatile. 팀 설정은 25/26 optimal 셸 유지(파운데이션-퍼스트, obs#6). 근거: 기존 7인=player_role_map optimal 처방, 영입 4인=transfer_targets 실측(에스투피냔 .946/가르나초 .911/만잠비 CAM .817/고메스 LDM .797). 피봇 좌우: 카마라 우중앙 앵커(duties#12)+고메스 좌측 우세 실측(.797 vs 우측 .638). 구조 판정: 더블 볼위닝 피봇→딥 창조 공백(보상: 파우 스텝업·만잠비 LDM 강하 dm_dlp .812·왓킨스 드롭), 좌측=공격 사이드(에스투피냔 오버랩+가르나초 인버티드), 캐비앗: 만잠비 halfwinger CAM-LM 충돌 0.72(가르나초 겹침)·시즌 초 실측 확인 항목. 변형 프리셋 후보: 만잠비 LDM+부엔디아 10번(잠긴 경기), 접전용 가르나초→Balanced형 스왑. 상세: reports/transfer-watch/2026-07-22.md','PROJECTED — 이적 미확정 포함(가르나초 MEDIUM-HIGH·에스투피냔 HIGH, 나머지 CONFIRMED/보유). 26/27 실측 축적 후 measured/optimal로 대체 예정. 만잠비·고메스·에스투피냔·가르나초 처방은 타클럽/대표팀 실측 기반이라 빌라 컨텍스트 재검증 필요.');
